UPDATE  /* CanMgmtMapper.setCanMgmt */
		PPS_CAN_USR_MST
SET     PROC_STATUS = #{procStatus}
        , PROC_DTTM = SYSDATE

        , PROC_DESC = #{procDesc}


        , CONN_RSLT_KEY = #{connRsltKey}


        , CONN_RSLT_TYPE = #{connRsltType}


        , CONN_RSLT_CD = #{connRsltCd}


        , CONN_RSLT_MSG = #{connRsltMsg}

WHERE   CONTRACT_NUM = #{contractNum}
AND		CUSTOMER_ID = #{customerId}
AND		SUBSCRIBER_NO = #{subscriberNo}
